// SPDX-License-Identifier: MIT
pragma solidity ^0.8.26;

contract LendingPool {
    error InsufficientCollateral();
    error OutstandingDebt();
    error InsufficientRepayment();

    mapping(address => uint256) public collateral;
    mapping(address => uint256) public principal;
    mapping(address => uint256) public lastBorrowTime;

    function deposit() external payable {
        collateral[msg.sender] += msg.value;
    }

    function borrow(uint256 amount) external {
        if ([[SLOT ltv_check]]) revert InsufficientCollateral();

        if (principal[msg.sender] > 0) {
            [[SLOT compound_step]]
        }

        principal[msg.sender] += amount;
        lastBorrowTime[msg.sender] = block.timestamp;

        payable(msg.sender).transfer(amount);
    }

    function repay() external payable {
        uint256 debt = getDebt(msg.sender);
        if (msg.value < debt) revert InsufficientRepayment();

        principal[msg.sender] = 0;
        lastBorrowTime[msg.sender] = 0;

        if (msg.value > debt) {
            payable(msg.sender).transfer(msg.value - debt);
        }
    }

    function withdraw(uint256 amount) external {
        if (principal[msg.sender] > 0) revert OutstandingDebt();
        if (amount > collateral[msg.sender]) revert InsufficientCollateral();

        collateral[msg.sender] -= amount;
        payable(msg.sender).transfer(amount);
    }

    function getDebt(address user) public view returns (uint256) {
        if (principal[user] == 0) return 0;

        uint256 elapsed = block.timestamp - lastBorrowTime[user];
        uint256 interest = [[SLOT interest_calc]];
        return principal[user] + interest;
    }
}
